ee:message.ee:set-payload:
%dw 2.0
output application/json

fun vaccinatedCount(state) = 
    (payload filter (($.STATE == state as String) and ($.CASE_TYPE == 'vaccinated') )
            map ($.COUNT))[0]

---
(payload groupBy ((item, index) -> item.STATE)
        mapObject ((value, key, index) -> (
            reportItem: {
                state: key,
                report: {
                    total: (value.COUNT reduce ((item, acc = 0) -> acc + item)) - ((vaccinatedCount(key) as Number default 0)),
                    (value map {
                        ($.CASE_TYPE) : $.COUNT
                    })
                }
            }
        ))).*reportItem  default  []
